export type QuoteContext = {
  yearsWithMHPCO: number;
  isFollowUp: boolean;
};

const POLICY_FEE = 5;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const BLOCK_SIZE = 3;
const BLOCK_PRICE = 60;

const COMPONENT_TYPES = ["rune", "moonstone"];

const isComponent = (item: { type: string }): boolean =>
  COMPONENT_TYPES.includes(item.type);

const basePremiumFor = (item: { type: string }): number => BASE_PREMIUM[item.type];

const componentGroupPremium = (type: string, count: number): number =>
  count === BLOCK_SIZE ? BLOCK_PRICE : count * BASE_PREMIUM[type];

export function quote(items: { type: string }[], context: QuoteContext): number {
  const componentBasePremium = COMPONENT_TYPES.reduce((sum, type) => {
    const count = items.filter((item) => item.type === type).length;
    return sum + componentGroupPremium(type, count);
  }, 0);

  const mainBasePremium = items
    .filter((item) => !isComponent(item))
    .reduce((sum, item) => sum + basePremiumFor(item), 0);

  return mainBasePremium + componentBasePremium + POLICY_FEE;
}

export function claim(): unknown {
  return undefined;
}

